"use client";

/**
 * Opener for the `socketAccordion` overlay.
 *
 * - `useOpenFullscreenSocketAccordion()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<FullscreenSocketAccordionController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "socketAccordion" as const;

export interface OpenFullscreenSocketAccordionOptions {
  triggerClassName?: string;
  triggerLabel?: string;
  taskId?: string;
  showTrigger?: boolean;
}

export interface FullscreenSocketAccordionHandle {
  close: () => void;
}

export function useOpenFullscreenSocketAccordion() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenFullscreenSocketAccordionOptions = {}): FullscreenSocketAccordionHandle => {
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          data: {
            triggerClassName: opts.triggerClassName,
            triggerLabel: opts.triggerLabel,
            taskId: opts.taskId,
            showTrigger: opts.showTrigger,
          },
        }),
      );
      return {
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function FullscreenSocketAccordionController(props: OpenFullscreenSocketAccordionOptions): null {
  const open = useOpenFullscreenSocketAccordion();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.triggerClassName, props.triggerLabel, props.taskId, props.showTrigger]);
  return null;
}
